// --- SUMMONING SEAL LOADING ---
const SummoningSeal = ({ onComplete }: { onComplete: () => void }) => {
  const [phase, setPhase] = useState(0);
  const [text, setText] = useState('');
  const targetText = 'ZEAL';
  const runes = 'ᚠᚢᚦᚨᚱᚲᚷᚹᚺᚾᛁᛃᛇᛈᛉᛊᛏᛒᛖᛗᛚᛜᛞᛟ';

  useEffect(() => {
    const phaseTimer = setTimeout(() => setPhase(1), 500);
    return () => clearTimeout(phaseTimer);
  }, []);

  useEffect(() => {
    if (phase < 2) return;
    let currentIndex = 0;
    const decodeInterval = setInterval(() => {
      if (currentIndex < targetText.length) {
        setText(() => {
          const decoded = targetText.slice(0, currentIndex + 1);
          const remaining = Array(targetText.length - currentIndex - 1)
            .fill(0)
            .map(() => runes[Math.floor(Math.random() * runes.length)])
            .join('');
          return decoded + remaining;
        });
        currentIndex++;
      } else {
        clearInterval(decodeInterval);
        setTimeout(() => setPhase(3), 800);
        setTimeout(() => setPhase(4), 2000);
        setTimeout(() => onComplete(), 3000);
      }
    }, 200);
    return () => clearInterval(decodeInterval);
  }, [phase, onComplete]);

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-[#010101]">
      <div className="absolute inset-0 flex items-center justify-center">
        <svg className="w-[500px] h-[500px] md:w-[700px] md:h-[700px]" viewBox="0 0 700 700">
          <defs>
            <linearGradient id="goldGrad" x1="0%" y1="0%" x2="100%" y2="100%">
              <stop offset="0%" stopColor="#C9A962" />
              <stop offset="50%" stopColor="#E8D5A3" />
              <stop offset="100%" stopColor="#8B7355" />
            </linearGradient>
          </defs>
          
          <g style={{ animation: 'spin 60s linear infinite', transformOrigin: '350px 350px' }}>
            <circle cx="350" cy="350" r="320" fill="none" stroke="url(#goldGrad)" strokeWidth="1" opacity={phase >= 1 ? 0.3 : 0} className="transition-opacity duration-1000" />
            <circle cx="350" cy="350" r="300" fill="none" stroke="#2a2a2a" strokeWidth="0.5" strokeDasharray="8 16" opacity={phase >= 1 ? 0.5 : 0} className="transition-opacity duration-1000" />
          </g>
          
          <g opacity={phase >= 1 ? 0.4 : 0} className="transition-opacity duration-1000">
            <polygon points="350,50 620,250 520,600 180,600 80,250" fill="none" stroke="url(#goldGrad)" strokeWidth="2" style={{ filter: 'drop-shadow(0 0 10px rgba(201,169,98,0.5))' }} />
          </g>
          
          <circle cx="350" cy="350" r="150" fill="none" stroke="url(#goldGrad)" strokeWidth="2" opacity={phase >= 2 ? 0.6 : 0} className="transition-opacity duration-1000" style={{ filter: 'drop-shadow(0 0 20px rgba(201,169,98,0.5))' }} />
          <circle cx="350" cy="350" r="100" fill="none" stroke="#C9A962" strokeWidth="1" opacity={phase >= 2 ? 0.4 : 0} className="transition-opacity duration-1000" />
        </svg>
      </div>

      <div className="relative z-10 text-center">
        <div className="mb-8" style={{ opacity: phase >= 2 ? 1 : 0, transition: 'opacity 1s' }}>
          <svg width="80" height="80" viewBox="0 0 100 100" className="mx-auto">
            <ellipse cx="50" cy="50" rx="45" ry="30" fill="none" stroke="#C9A962" strokeWidth="2" />
            <circle cx="50" cy="50" r="20" fill="#C9A962" opacity="0.8" />
            <circle cx="50" cy="50" r="8" fill="#010101" />
          </svg>
        </div>
        
        <h1 className="text-6xl md:text-8xl font-cinzel tracking-[0.5em] text-transparent bg-clip-text bg-gradient-to-b from-[#E8D5A3] via-[#C9A962] to-[#8B7355]" style={{ opacity: phase >= 2 ? 1 : 0, textShadow: phase >= 3 ? '0 0 40px rgba(201,169,98,0.5)' : 'none', transition: 'all 1s' }}>
          {text || '    '}
        </h1>
        
        <div className="flex gap-3 justify-center mt-12">
          {[0, 1, 2, 3].map((i) => (
            <div key={i} className="w-2 h-2 rounded-full transition-all duration-500" style={{ backgroundColor: phase >= i ? '#C9A962' : '#333', transform: phase === i ? 'scale(1.5)' : 'scale(1)', boxShadow: phase >= i ? '0 0 10px rgba(201,169,98,0.5)' : 'none' }} />
          ))}
        </div>
      </div>

      <button onClick={onComplete} className="fixed bottom-6 right-6 text-zinc-700 text-[10px] font-montserrat uppercase tracking-widest hover:text-[#C9A962] transition-colors z-[101]">
        Skip Intro
      </button>
    </div>
  );
};

