// --- VIRTUAL DRESSING ROOM ---
const VirtualDressingRoom = ({
  isOpen, onClose, initialProduct, onAddToCart, cartItems
}: { isOpen: boolean; onClose: () => void; initialProduct?: Product; onAddToCart: (item: CartItem) => void; cartItems: CartItem[]; }) => {
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(initialProduct || null);
  const [selectedType, setSelectedType] = useState<'tshirt' | 'hoodie'>('tshirt');
  const [selectedColor, setSelectedColor] = useState('black');
  const [selectedSize, setSelectedSize] = useState('M');
  const [view, setView] = useState<'front' | 'back'>('back');
  const [zoom, setZoom] = useState(1);

  useEffect(() => { if (initialProduct) setSelectedProduct(initialProduct); }, [initialProduct]);
  if (!isOpen || !selectedProduct) return null;

  // Price calculation would go here when products have prices
  const inCart = cartItems.some(item => item.id === selectedProduct.id);

  const handleAdd = () => {
    if (selectedProduct.price === 0) return;
    onAddToCart({ ...selectedProduct, quantity: 1, size: selectedSize, color: selectedColor, type: selectedType });
  };

  return (
    <div className="fixed inset-0 z-[90] bg-black/95 flex">
      <button onClick={onClose} className="absolute top-4 right-4 text-zinc-500 hover:text-zinc-300 z-50"><X className="w-8 h-8" /></button>
      
      <div className="flex-1 flex items-center justify-center p-8 relative">
        <div className="relative transition-transform duration-500" style={{ transform: `scale(${zoom})` }}>
          <img src={view === 'back' ? selectedProduct.images.back : selectedProduct.images.front} alt={selectedProduct.name} className="max-h-[70vh] max-w-full object-contain drop-shadow-2xl opacity-50" />
          <div className="absolute inset-0 bg-[#C9A962]/5 blur-3xl -z-10" />
        </div>

        <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-4 bg-zinc-900/80 px-6 py-3 rounded-full">
          <button onClick={() => setView(v => v === 'front' ? 'back' : 'front')} className="text-zinc-400 hover:text-[#C9A962]"><RotateCw className="w-5 h-5" /></button>
          <div className="w-px h-6 bg-zinc-700" />
          <button onClick={() => setZoom(z => Math.max(0.7, z - 0.1))} className="text-zinc-400 hover:text-[#C9A962]"><ZoomOut className="w-5 h-5" /></button>
          <span className="text-zinc-500 text-sm font-montserrat">{Math.round(zoom * 100)}%</span>
          <button onClick={() => setZoom(z => Math.min(1.3, z + 0.1))} className="text-zinc-400 hover:text-[#C9A962]"><ZoomIn className="w-5 h-5" /></button>
        </div>
      </div>

      <div className="w-96 bg-[#0a0a0a] border-l border-zinc-800 p-6 overflow-y-auto">
        <h2 className="text-2xl font-cinzel text-zinc-300 mb-2">{selectedProduct.name}</h2>
        <p className="text-zinc-600 font-montserrat text-sm mb-6">{selectedProduct.description}</p>

        <div className="mb-4">
          <label className="text-zinc-500 text-xs uppercase tracking-wider mb-2 block">Type</label>
          <div className="flex gap-2">
            {(['tshirt', 'hoodie'] as const).map((type) => (
              <button key={type} onClick={() => setSelectedType(type)} className={`flex-1 py-2 text-xs uppercase tracking-wider transition-all ${selectedType === type ? 'bg-[#C9A962] text-black' : 'bg-zinc-900 text-zinc-500 hover:text-zinc-300'}`}>{type} ({type === 'tshirt' ? 'Base' : '+R350'})</button>
            ))}
          </div>
        </div>

        <div className="mb-4">
          <label className="text-zinc-500 text-xs uppercase tracking-wider mb-2 block">Color</label>
          <div className="flex gap-2">
            {['black', 'white', 'charcoal'].map((color) => (
              <button key={color} onClick={() => setSelectedColor(color)} className={`w-12 h-12 rounded transition-all ${selectedColor === color ? 'ring-2 ring-[#C9A962]' : ''}`} style={{ backgroundColor: color === 'charcoal' ? '#333' : color, border: color === 'white' ? '1px solid #444' : 'none' }} />
            ))}
          </div>
        </div>

        <div className="mb-6">
          <label className="text-zinc-500 text-xs uppercase tracking-wider mb-2 block">Size</label>
          <div className="flex gap-2">
            {['S', 'M', 'L', 'XL', 'XXL'].map((size) => (
              <button key={size} onClick={() => setSelectedSize(size)} className={`w-10 h-10 text-sm transition-all ${selectedSize === size ? 'bg-[#C9A962] text-black' : 'bg-zinc-900 text-zinc-500 hover:text-zinc-300'}`}>{size}</button>
            ))}
          </div>
        </div>

        <button onClick={handleAdd} disabled={selectedProduct.price === 0} className="w-full py-4 bg-[#C9A962] text-black font-cinzel uppercase tracking-wider hover:bg-[#E8D5A3] transition-colors mb-4 disabled:opacity-50">
          {selectedProduct.price === 0 ? 'Coming Soon' : (inCart ? 'Add Another' : 'Add to Cart')}
        </button>

        <div className="mt-8 pt-8 border-t border-zinc-800">
          <label className="text-zinc-500 text-xs uppercase tracking-wider mb-4 block">Browse Collection</label>
          <div className="grid grid-cols-3 gap-2 max-h-48 overflow-y-auto">
            {PRODUCTS.map((p) => (
              <button key={p.id} onClick={() => setSelectedProduct(p)} className={`relative aspect-square overflow-hidden ${selectedProduct.id === p.id ? 'ring-2 ring-[#C9A962]' : ''}`}>
                <img src={p.images.back} alt={p.name} className="w-full h-full object-cover opacity-50" />
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

// --- VIRTUAL CLOSET ---
const VirtualCloset = ({ isOpen, onClose, onOpenDressingRoom, cartItems }: { isOpen: boolean; onClose: () => void; onOpenDressingRoom: (product: Product) => void; cartItems: CartItem[]; }) => {
  const [favorites, setFavorites] = useState<string[]>(() => { const saved = localStorage.getItem('zeal-favorites'); return saved ? JSON.parse(saved) : []; });
  const [filter, setFilter] = useState<'all' | 'favorites'>('all');

  useEffect(() => { localStorage.setItem('zeal-favorites', JSON.stringify(favorites)); }, [favorites]);
  const toggleFavorite = (id: string) => { setFavorites(prev => prev.includes(id) ? prev.filter(f => f !== id) : [...prev, id]); };
  const filteredProducts = PRODUCTS.filter(p => filter === 'favorites' ? favorites.includes(p.id) : true);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[90] bg-black/95 flex flex-col">
      <div className="flex items-center justify-between p-6 border-b border-zinc-800">
        <h2 className="text-2xl font-cinzel text-zinc-300">Virtual Closet</h2>
        <div className="flex items-center gap-4">
          <div className="flex gap-2">
            {(['all', 'favorites'] as const).map((f) => (
              <button key={f} onClick={() => setFilter(f)} className={`px-3 py-1 text-[10px] uppercase tracking-wider transition-all ${filter === f ? 'bg-[#C9A962] text-black' : 'bg-zinc-900 text-zinc-500 hover:text-zinc-300'}`}>{f} ({f === 'favorites' ? favorites.length : PRODUCTS.length})</button>
            ))}
          </div>
          <button onClick={onClose} className="text-zinc-500 hover:text-zinc-300"><X className="w-6 h-6" /></button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6">
        <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4">
          {filteredProducts.map((product) => (
            <div key={product.id} className="group relative bg-zinc-900/50 border border-zinc-800 hover:border-[#C9A962]/30 transition-all cursor-pointer" onClick={() => onOpenDressingRoom(product)}>
              <div className="aspect-[3/4] overflow-hidden">
                <img src={product.images.back} alt={product.name} className="w-full h-full object-cover group-hover:scale-105 transition-transform opacity-50" />
              </div>
              <div className="absolute top-2 right-2">
                <button onClick={(e) => { e.stopPropagation(); toggleFavorite(product.id); }} className={`p-1 ${favorites.includes(product.id) ? 'text-[#C9A962]' : 'text-zinc-600 hover:text-[#C9A962]'}`}><Heart className={`w-4 h-4 ${favorites.includes(product.id) ? 'fill-current' : ''}`} /></button>
              </div>
              <div className="p-3">
                <p className="text-zinc-500 text-xs font-cinzel">{product.name}</p>
                {cartItems.some(i => i.id === product.id) && <p className="text-[#C9A962] text-[10px] uppercase mt-1">In Cart</p>}
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

// --- CART ---
const Cart = ({ isOpen, onClose, items, onUpdateQuantity, onRemove }: { isOpen: boolean; onClose: () => void; items: CartItem[]; onUpdateQuantity: (id: string, qty: number) => void; onRemove: (id: string) => void; }) => {
  const total = items.reduce((sum, item) => sum + item.price * item.quantity, 0);
  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[80]">
      <div className="absolute inset-0 bg-black/80" onClick={onClose} />
      <div className="absolute right-0 top-0 bottom-0 w-full max-w-md bg-[#0a0a0a] border-l border-zinc-800 p-6 overflow-y-auto">
        <div className="flex justify-between items-center mb-8">
          <h2 className="text-xl font-cinzel text-zinc-300 tracking-wider">Your Cart</h2>
          <button onClick={onClose} className="text-zinc-600 hover:text-zinc-400"><X className="w-6 h-6" /></button>
        </div>

        {items.length === 0 ? (
          <div className="text-center py-20 text-zinc-600"><ShoppingBag className="w-12 h-12 mx-auto mb-4 opacity-30" /><p className="font-montserrat text-sm">Your cart is empty</p></div>
        ) : (
          <>
            <div className="space-y-4 mb-8">
              {items.map((item) => (
                <div key={`${item.id}-${item.size}-${item.color}-${item.type}`} className="flex gap-4 p-4 bg-zinc-900/50 rounded-lg">
                  <div className="w-20 h-20 bg-zinc-800 rounded flex items-center justify-center"><img src={item.images.back} alt="" className="w-16 h-16 object-cover opacity-50" /></div>
                  <div className="flex-1">
                    <h4 className="font-cinzel text-zinc-300 text-sm">{item.name}</h4>
                    <p className="text-zinc-600 text-xs font-montserrat">{item.color} / {item.size} / {item.type}</p>
                    <p className="text-[#C9A962] font-montserrat text-sm mt-1">R{item.price}</p>
                  </div>
                  <div className="flex flex-col items-end gap-2">
                    <button onClick={() => onRemove(`${item.id}-${item.size}-${item.color}-${item.type}`)} className="text-zinc-600 hover:text-red-500"><Trash2 className="w-4 h-4" /></button>
                    <div className="flex items-center gap-2">
                      <button onClick={() => onUpdateQuantity(`${item.id}-${item.size}-${item.color}-${item.type}`, Math.max(0, item.quantity - 1))} className="w-6 h-6 bg-zinc-800 rounded flex items-center justify-center text-zinc-400 hover:bg-zinc-700"><Minus className="w-3 h-3" /></button>
                      <span className="text-zinc-300 text-sm font-montserrat w-6 text-center">{item.quantity}</span>
                      <button onClick={() => onUpdateQuantity(`${item.id}-${item.size}-${item.color}-${item.type}`, item.quantity + 1)} className="w-6 h-6 bg-zinc-800 rounded flex items-center justify-center text-zinc-400 hover:bg-zinc-700"><Plus className="w-3 h-3" /></button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
            <div className="border-t border-zinc-800 pt-6">
              <div className="flex justify-between mb-4"><span className="text-zinc-500 font-montserrat">Subtotal</span><span className="text-zinc-300 font-cinzel">R{total}</span></div>
              <button className="w-full py-4 bg-[#C9A962] text-black font-cinzel text-sm tracking-[0.2em] uppercase hover:bg-[#E8D5A3] transition-colors">Checkout</button>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

// --- ADMIN PANEL ---
const AdminPanel = ({ onClose }: { onClose: () => void }) => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleLogin = () => {
    if (password === '66696') { setIsAuthenticated(true); setError(''); }
    else { setError('Invalid password'); }
  };

  if (!isAuthenticated) {
    return (
      <div className="fixed inset-0 z-[100] bg-black/95 flex items-center justify-center p-6">
        <div className="bg-[#0a0a0a] border border-zinc-800 p-8 rounded-lg max-w-md w-full">
          <div className="text-center mb-8"><Lock className="w-12 h-12 text-[#C9A962] mx-auto mb-4" /><h2 className="text-2xl font-cinzel text-zinc-300">Sanctum Access</h2></div>
          <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleLogin()} placeholder="Password" className="w-full bg-zinc-900 border border-zinc-800 p-4 text-zinc-300 font-montserrat mb-4 focus:border-[#C9A962] outline-none" />
          {error && <p className="text-red-500 text-sm mb-4">{error}</p>}
          <button onClick={handleLogin} className="w-full py-3 bg-[#C9A962] text-black font-cinzel uppercase tracking-wider hover:bg-[#E8D5A3] transition-colors">Enter Sanctum</button>
          <button onClick={onClose} className="w-full py-3 mt-2 text-zinc-600 font-montserrat text-sm hover:text-zinc-400">Return</button>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-[100] bg-[#010101]/98 overflow-y-auto">
      <div className="max-w-6xl mx-auto p-6 md:p-12">
        <div className="flex justify-between items-center mb-12 border-b border-zinc-800 pb-6">
          <div><h2 className="text-2xl font-cinzel text-zinc-300 tracking-wider">The Inner Sanctum</h2><p className="text-zinc-600 text-xs mt-2">Covenant Operations</p></div>
          <button onClick={onClose} className="text-zinc-600 hover:text-zinc-400"><X className="w-6 h-6" /></button>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          {[{ label: 'Total Revenue', value: 'R0', icon: CreditCard }, { label: 'Orders', value: '0', icon: Package }, { label: 'Products', value: PRODUCTS.length.toString(), icon: BarChart3 }].map((stat, i) => (
            <div key={i} className="bg-zinc-900/50 p-6 border border-zinc-800"><stat.icon className="w-5 h-5 text-[#C9A962] mb-4" /><p className="text-2xl font-cinzel text-zinc-300">{stat.value}</p><p className="text-zinc-600 text-xs font-montserrat mt-1">{stat.label}</p></div>
          ))}
        </div>
      </div>
    </div>
  );
};

// --- SHOP SECTION ---
const ShopSection = ({ onAddToCart, onOpenDressingRoom }: { onAddToCart: (item: CartItem) => void; onOpenDressingRoom: (product: Product) => void; }) => (
  <section id="shop" className="py-32 px-6 lg:px-24 bg-[#010101]">
    <div className="max-w-7xl mx-auto">
      <div className="text-center mb-16">
        <p className="text-[#C9A962] font-cinzel tracking-[0.5em] text-xs mb-4">THE COLLECTION</p>
        <h2 className="text-4xl md:text-6xl font-cinzel text-zinc-300 mb-6">Coming Soon</h2>
        <p className="text-zinc-600 max-w-xl mx-auto font-montserrat text-sm">New designs launching soon. Join the covenant to be first to know.</p>
      </div>
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {PRODUCTS.map((product) => (
          <ProductCard key={product.id} product={product} onAddToCart={onAddToCart} onOpenDressingRoom={onOpenDressingRoom} />
        ))}
      </div>
    </div>
  </section>
);

// --- MAIN APP ---
function App() {
  const [appState, setAppState] = useState<'loading' | 'intro' | 'ready'>('loading');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [isDressingRoomOpen, setIsDressingRoomOpen] = useState(false);
  const [isClosetOpen, setIsClosetOpen] = useState(false);
  const [selectedProduct, setSelectedProduct] = useState<Product | undefined>();
  const [scrollProgress, setScrollProgress] = useState(0);

  useEffect(() => {
    const handleScroll = () => { setScrollProgress((window.scrollY / (document.documentElement.scrollHeight - window.innerHeight)) * 100); };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleAddToCart = (item: CartItem) => {
    const itemKey = `${item.id}-${item.size}-${item.color}-${item.type}`;
    setCart((prev: CartItem[]) => {
      const existing = prev.find((i: CartItem) => `${i.id}-${i.size}-${i.color}-${i.type}` === itemKey);
      if (existing) return prev.map((i: CartItem) => `${i.id}-${i.size}-${i.color}-${i.type}` === itemKey ? { ...i, quantity: i.quantity + item.quantity } : i);
      return [...prev, item];
    });
    setIsCartOpen(true);
  };

  const handleUpdateQuantity = (itemKey: string, quantity: number) => {
    if (quantity === 0) setCart((prev: CartItem[]) => prev.filter((i: CartItem) => `${i.id}-${i.size}-${i.color}-${i.type}` !== itemKey));
    else setCart((prev: CartItem[]) => prev.map((i: CartItem) => `${i.id}-${i.size}-${i.color}-${i.type}` === itemKey ? { ...i, quantity } : i));
  };

  const handleRemove = (itemKey: string) => setCart((prev: CartItem[]) => prev.filter((i: CartItem) => `${i.id}-${i.size}-${i.color}-${i.type}` !== itemKey));
  const handleOpenDressingRoom = (product: Product) => { setSelectedProduct(product); setIsDressingRoomOpen(true); };

  if (appState === 'loading') return <SummoningSeal onComplete={() => setAppState('intro')} />;
  if (appState === 'intro') return <Hero onEnter={() => setAppState('ready')} />;

  return (
    <div className="bg-[#010101] min-h-screen text-gray-300 font-montserrat">
      <Navbar cartCount={cart.reduce((sum, item) => sum + item.quantity, 0)} onOpenAdmin={() => setIsAdminOpen(true)} onOpenCart={() => setIsCartOpen(true)} onOpenDressingRoom={() => setIsDressingRoomOpen(true)} onOpenCloset={() => setIsClosetOpen(true)} scrollProgress={scrollProgress} />
      <main>
        <ShopSection onAddToCart={handleAddToCart} onOpenDressingRoom={handleOpenDressingRoom} />
        <section id="about" className="py-32 px-6 lg:px-24 bg-[#050505]">
          <div className="max-w-4xl mx-auto text-center">
            <p className="text-[#C9A962] font-cinzel tracking-[0.5em] text-xs mb-6">THE PHILOSOPHY</p>
            <h2 className="text-3xl md:text-5xl font-cinzel text-zinc-300 mb-8">More Than Apparel</h2>
            <p className="text-zinc-500 font-montserrat leading-relaxed">ZEAL represents the intersection of occult symbolism and premium streetwear. Each piece is a statement of intent, a wearable philosophy.</p>
          </div>
        </section>
        <footer className="py-20 px-6 border-t border-zinc-900 bg-[#010101]">
          <div className="max-w-6xl mx-auto flex flex-col items-center">
            <h3 className="text-3xl font-cinzel text-zinc-500 tracking-[0.5em] mb-4">ZEAL</h3>
            <p className="text-zinc-800 text-[10px] tracking-[0.3em]">© 2026 ZEAL • AS ABOVE SO BELOW</p>
          </div>
        </footer>
      </main>
      <Cart isOpen={isCartOpen} onClose={() => setIsCartOpen(false)} items={cart} onUpdateQuantity={handleUpdateQuantity} onRemove={handleRemove} />
      <VirtualDressingRoom isOpen={isDressingRoomOpen} onClose={() => setIsDressingRoomOpen(false)} initialProduct={selectedProduct} onAddToCart={handleAddToCart} cartItems={cart} />
      <VirtualCloset isOpen={isClosetOpen} onClose={() => setIsClosetOpen(false)} onOpenDressingRoom={handleOpenDressingRoom} cartItems={cart} />
      {isAdminOpen && <AdminPanel onClose={() => setIsAdminOpen(false)} />}
    </div>
  );
}

export default App;
